function user_files_upload_handler() {
    if ( ! empty( $_FILES ) && isset( $_POST['upload'] ) ) {
        $upload_dir = wp_upload_dir();
        $allowed_types = array(
            'image/*',
            'application/pdf',
            'application/msword',
            'application/vnd.openxmlformats-officedocument.wordprocessingml.document'
        );
        
        if ( empty( $_FILES['file']['name'] ) ) {
            return;
        }
        
        $upload_overrides = array(
            'path' => wp_upload_dir()['path'],
            'url'  => wp_upload_dir()['url']
        );
        
        $overrides = apply_filters('regenerate_image', $upload_overrides);
        
        $file = $_FILES['file'];
        $uploaded_file = wp_handle_upload($file, $overrides);
        
        if ( $uploaded_file && ! is_wp_error( $uploaded_file ) ) {
            echo 'File uploaded successfully.';
        } else {
            echo 'Error uploading file.';
        }
    }
}

function enqueue_scripts() {
    wp_enqueue_script('user-files-upload-handler', plugins_url('/js/user-files-upload-handler.js', __FILE__), array('jquery'));
}

add_action('admin_enqueue_scripts', 'enqueue_scripts');
add_action('wp_ajax_user_files_upload_handler', 'user_files_upload_handler');

// Save uploaded files in a custom directory
function save_uploaded_file($file) {
    $upload_dir = wp_upload_dir();
    $dir_path = $upload_dir['path'] . '/user-files';
    
    if ( ! is_dir( $dir_path ) ) {
        mkdir( $dir_path, 0777, true );
    }
    
    move_uploaded_file($file, $dir_path . '/' . basename($file));
}

add_filter('wp_handle_upload', 'save_uploaded_file');